args.sparql:
SELECT ?game ?gameLabel ?villain ?villainLabel WHERE {
  wd:Q507898 wdt:P178 ?game.
  ?game wdt:P31 wd:Q7889.
  ?game wdt:P1035 ?villain.
  OPTIONAL { ?game rdfs:label ?gameLabel. FILTER (LANG(?gameLabel) = "en") }
  OPTIONAL { ?villain rdfs:label ?villainLabel. FILTER (LANG(?villainLabel) = "en") }
}

SELECT ?game ?gameLabel ?villain ?villainLabel WHERE {
  wd:Q507898 wdt:P178 ?game.
  ?game wdt:P31 wd:Q7889.
  ?game wdt:P7047 ?villain.
  OPTIONAL { ?game rdfs:label ?gameLabel. FILTER (LANG(?gameLabel) = "en") }
  OPTIONAL { ?villain rdfs:label ?villainLabel. FILTER (LANG(?villainLabel) = "en") }
}

SELECT DISTINCT ?game ?gameLabel ?villain ?villainLabel WHERE {
  wd:Q507898 wdt:P178 ?game.
  ?game wdt:P31 wd:Q7889.
  ?game wdt:P1327 ?character.
  ?character wdt:P1667 ?role.
  ?character rdfs:label ?villainLabel.
  FILTER (LANG(?villainLabel) = "en");
  ?role rdfs:label ?roleLabel.
  FILTER (LANG(?roleLabel) = "en" && (REGEX(LCASE(?roleLabel), "villain") || REGEX(LCASE(?roleLabel), "antagonist")));
  OPTIONAL { ?game rdfs:label ?gameLabel FILTER (LANG(?gameLabel) = "en") }
}
